int http_send_file(int dst_fd, int src_fd) {
    const int buf_size = 4096;
    char buf[buf_size];
    ssize_t bytes_read = read(src_fd, buf, buf_size);
    int status = 0;

    while (bytes_read > 0) {
        status = http_send_data(dst_fd, buf, bytes_read);
        if (status < 0) return status;

        bytes_read = read(src_fd, buf, buf_size);
    }

    return status;
}
```

